import { Link, useLocation } from 'react-router-dom';
import { useState, useEffect } from 'react';

export default function Header() {
  const location = useLocation();
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const isHomePage = location.pathname === '/';

  return (
    <header className={`bg-gradient-to-br from-slate-800 via-slate-900 to-slate-950 text-white py-4 sticky top-0 z-50 shadow-lg transition-all duration-300 ${isScrolled ? 'shadow-2xl shadow-black/20' : ''}`}>
      <div className="container mx-auto px-2">
        <div className="flex flex-col lg:flex-row items-center justify-between space-y-4 lg:space-y-0">
          <div className="flex items-center space-x-4 group">
            <div className="w-14 h-14 bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl flex items-center justify-center shadow-lg group-hover:scale-105 transition-transform duration-300">
              <i className="fas fa-bolt text-2xl text-white"></i>
            </div>
            <div>
              <div className="hidden lg:block">
                <h1 className="text-lg font-semibold text-white tracking-wide">Devis décennale{' '}
                  Electricien</h1>
                <p className="text-xs text-blue-400">en quelques clics</p>
              </div>
              <div className="lg:hidden">
                <h1 className="text-sm font-semibold text-white">Décennale</h1>
                <p className="text-xs text-blue-400">Electricien</p>
              </div>
            </div>
          </div>

          <div className="flex items-center space-x-4 group">
            <div className="p-3 bg-slate-700/50 rounded-2xl icon-bounce shadow-lg group-hover:bg-slate-700 transition-colors duration-300">
              <i className="fas fa-phone text-xl text-blue-400"></i>
            </div>
            <div>
              <span className="text-sm text-slate-300 block">Conseil personnalisé</span>
              <a href="tel:0182834800" className="text-xl font-bold text-white hover:text-blue-400 transition-colors duration-300 flex items-center">
                01 82 83 48 00
                <span className="ml-2 text-xs bg-green-500/20 text-green-400 px-2 py-0.5 rounded-full">
                  <i className="fas fa-check mr-1"></i>Disponible
                </span>
              </a>
            </div>
          </div>
        </div>
      </div>
    </header>
  );
}
